form:Form.form:Scripts:
		var LiqCloses;  
var MyLICSel=null;
var MyHORSel=null;
var Guias=null;

var MyOBJ;
var MyDAT=new Array();

function Obtener(NAME, SQL, PARAM)
{ 
	var proxy;
	var RESULT;
	var retval;
	var t;

	proxy=new NomadProxy();
	if (Guias==null) Guias=proxy.SQLService().GetOBJ(Ctrl("main").getResource("GUIAS"),PARAM);

	RESULT=Guias[SQL];

	MyDAT[NAME]=new Object(); 
	MyDAT[NAME].name=NAME;
	MyDAT[NAME].arr=new Array();
	MyDAT[NAME].def=null;
	MyDAT[NAME].sel="";
	MyDAT[NAME].cont="";    

	for (t=0; t<RESULT.Child.length; t++)
	{
		MyDAT[NAME].arr[RESULT.Child[t].id.toString()]=RESULT.Child[t];
		if (MyDAT[NAME].def==null) MyDAT[NAME].def=RESULT.Child[t];
	}

	return MyDAT[NAME];
}

function SetData(NAME, KEY)
{
	if (Ctrl("main").GetMode()!="EDIT") return;

	MyDAT[NAME].sel=KEY;     
	if (MyDAT[NAME].cont!="") DrawReference(MyDAT[NAME], MyDAT[NAME].cont);
}

function DrawReference(myOBJ, ContainerName)
{                     
	var HTMLoutput="", key;
	var TrgObj=document.getElementById(ContainerName);

	myOBJ.cont=ContainerName;
	HTMLoutput+="<TABLE style='width:99%;cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;background-color:#F0F0D0;' >";
	for (key in myOBJ.arr)
	{
		HTMLoutput+="<TR style='height:20px;"+(key==myOBJ.sel?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD onclick='SetData(\""+myOBJ.name+"\",\""+key+"\");' style='border-bottom:1px dotted #808080;width:30px;font-size:1px;' ><div style='padding:0px;height:12px;border-left:2px solid #"+myOBJ.arr[key].color+";border-right:2px solid #"+myOBJ.arr[key].color+";' ><div style='position:relative;top:4px;height:4px;width:100%;background-color:#"+myOBJ.arr[key].color+";' ></div></div></TD>"
		           +"<TD onclick='SetData(\""+myOBJ.name+"\",\""+key+"\");' style='border-bottom:1px dotted #808080;' >"+myOBJ.arr[key].label+"</TD>"
		           +"</TR>";
	}
	HTMLoutput+="</TABLE>";

	TrgObj.style.height=TrgObj.offsetHeight+"px";
	TrgObj.innerHTML=HTMLoutput;
}

function LoadReferences()
{	
	var myDate=Ctrl('ESPERANZA_PERIODO').GetXValue() + '01';	
	var PARAM = "<DATO oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+ "\" f_desde=\""+myDate+"\"/>";	
	//Referencias

	aux=Obtener("TUR", "TURNOS", PARAM);        DrawReference(aux, "REFERENCIA_TUR");
	aux=Obtener("LIC", "TIPOS_DE_HORA", PARAM); DrawReference(aux, "REFERENCIA_LIC");
	aux=Obtener("HOR", "HORARIOS", PARAM);      DrawReference(aux, "REFERENCIA_HOR");

	if(Guias.cont > 200)  
	{
		Ctrl("label_turnos").SetXValue("Turnos (solo periodo actual)");
		Ctrl("label_licencias").SetXValue("Licencias (solo periodo actual)");	
	}
	else                                         
	{
		Ctrl("label_turnos").SetXValue("Turnos");
		Ctrl("label_licencias").SetXValue("Licencias");
	}

	//Cargo el Rango
	NomadTimeout("OnChangePeriodo(); RefreshControls();", 100, "Cargando la Esperanza...");
}

function RefreshMonth()
{
	NomadTimeout("OnChangePeriodo();", 1000, "Cargando la Esperanza...");
}        

function OnLoad()
{
	//Inicio el Periodo	
	if (Ctrl("ESPERANZA_PERIODO").GetXValue()=="") 
	{
		if (Ctrl("periodo").GetXValue()!="") 
			Ctrl("ESPERANZA_PERIODO").SetXValue(Ctrl("periodo").GetXValue()+'01');
		else
			Ctrl("ESPERANZA_PERIODO").SetXValue(date2str(NowDate()).substr(0,6));
	}

	//Obtengo los Parametros
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var lastDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);

	//Creo el CONTROL
	MyOBJ=HTMLTimeBarSelected("ESPERANZA","",ChangeTime,OnClickHorario);
	MyOBJ.SetAxisMode("SERIE/DATE");
	MyOBJ.SetAxisDate(objMONTH.GetXValue()+"01",date2str(lastDate), 1, 1, 12);
	MyOBJ.ShowMonth=false;

 	//Agrego la Serie
	MyOBJ.AddSerie("BLQ", "Cerrado"  ,"Liquidaciones Cerradas");
	MyOBJ.AddSerie("HOR", "Horarios" ,"Horarios Asignados"    );
	MyOBJ.AddSerie("LIC", "Licencias","Licencias Definidas"   );
	MyOBJ.AddSerie("TUR", "Turnos"   ,"Turnos Asignados"      );

	//Dibujo la Lista VACIA
	MyOBJ.Draw();


	LiqCloses=new NomadXML(Ctrl("main").GetLastDoc("LIQ"  ));


	//Cargo las Referencias
	NomadTimeout("LoadReferences();", 100, "Cargando Referencias...");
}                   

function PrevMonth()
{
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var NewDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10)-2, 1);
	objMONTH.SetXValue((NewDate.getFullYear()*100+(NewDate.getMonth()+1)).toString());
	RefreshMonth();
}                        

function NextMonth()
{
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var NewDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);
	objMONTH.SetXValue((NewDate.getFullYear()*100+(NewDate.getMonth()+1)).toString());
	RefreshMonth();
}                   


function RefreshSerie(MyOBJ, myserie)
{	
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var ff, fi, now, cur, MyROW, t, d, oi_licencia, oi_horario, oi_escuadra, horDef;
	var firstDate=date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10)-1, 1));
	var lastDate =date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1));

	//Limpio el DIA     
	MyOBJ.ClearValue(myserie);     

	if (myserie=="BLQ")	
	{ 
		var dias;    
		if(Ctrl('CantidadDiasModificar') != undefined && Ctrl('CantidadDiasModificar').GetXValue() !='' )
			dias = Ctrl('CantidadDiasModificar').GetXValue();
		else
			dias = 180;
		//Dias Bloqueados por antiguedad
		now=date2int(NowDate())-dias;

		if (firstDate<=now)
		{
			if (now>lastDate) now=lastDate;

			MyOBJ.SetValue(
				"BLQ",
				firstDate,
				now+1,
				"Bloqueado",
				"AA0000",
				"AA0000",
				"Bloqueado por ser anterior a "+dias+" dias"	
			);
		}

		//Dias Bloqueados por liquidaciones cerradas
		for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
		{       
			fi=date2int(cur.GetAttrDateTime("f_ini"));
			ff=date2int(cur.GetAttrDateTime("f_fin"));
			if (ff<firstDate) continue;
			if (fi>lastDate) continue;

			MyOBJ.SetValue(
				"BLQ",
				fi,
				ff+1,
				"Bloqueado",
				"AA0000",
				"AA0000",
				"Bloqueado porque hay una liquidacion cerrada"	
			);
		}  
	}

	if (myserie=="LIC")	
	{

		for (t=0; t<Ctrl("arrLicencias").CountRow(); t++)
		{
			MyROW=Ctrl("arrLicencias").GetRow(t);

			oi_licencia=MyROW.GetAttr("oi_licencia");
			fi=date2int(str2date(MyROW.GetAttr("f_inicio")));
			ff=date2int(str2date(MyROW.GetAttr("f_fin")));
			if (MyROW.GetAttr("f_interrupcion")!="") ff=date2int(str2date(MyROW.GetAttr("f_interrupcion")));

			if (ff<firstDate) continue;
			if (fi>lastDate) continue;        

			dd=null;
			for (key in MyDAT["LIC"].arr)
				if (MyDAT["LIC"].arr[key].lic==oi_licencia)
					dd=MyDAT["LIC"].arr[key];

			MyOBJ.SetValue(
				"LIC",
				fi,
				ff+1,
				"Licencia",
				dd==null?"AA0000":dd.color,
				dd==null?"AA0000":dd.color,
				"Licencia "+(dd==null?"":dd.label)+" desde "+int2date(fi)+(MyROW.GetAttr("f_interrupcion")==""?" hasta ":" interrumpida ")+int2date(ff)
			);
		}
	}

	if (myserie=="HOR")	
	{
		for (t=0; t<Ctrl("arrHorarios").CountRow(); t++)
		{
			MyROW=Ctrl("arrHorarios").GetRow(t);

			fi =date2int(str2date(MyROW.GetAttr("f_fechaInicio")));
			fff=MyROW.GetAttr("f_fechaFin");
			oi_horario=MyROW.GetAttr("oi_horario");

			if (fff=="") ff=lastDate;
		          else ff=date2int(str2date(fff))-1;
			if (ff<firstDate) continue;
			if (fi>lastDate) continue;        

			GetDataSel(MyDAT, oi_horario);
			dd=MyDAT["HOR"].arr[oi_horario];

			MyOBJ.SetValue(
				"HOR",
				fi,
				ff+1,
				"Horario",
				dd.color,
				dd.color,
				"Horario "+dd.label+" desde " + int2date(fi)+((fff=="")?"":" hasta "+int2date(ff))
			);
		}
	}

	if (myserie=="TUR")	
	{    
		arr =new Array();

		//inicializo el Array
		for (t=0; t<lastDate-firstDate; t++) arr[t]="0";

		//recorro los dias
		for (t=0; t<lastDate-firstDate; t++)
		{      

			oi_horario ="";
			oi_escuadra="";

			//obtengo el Horario
			for (d=0; d<Ctrl("arrHorarios").CountRow(); d++)
			{
				MyROW=Ctrl("arrHorarios").GetRow(d);

				fi =date2int(str2date(MyROW.GetAttr("f_fechaInicio")));
				ff =MyROW.GetAttr("f_fechaFin");
				if (ff=="") ff=lastDate; else ff=date2int(str2date(ff))-1;

				if (t+firstDate>=fi && t+firstDate<=ff)
				{
					oi_horario =MyROW.GetAttr("oi_horario");
					oi_escuadra=MyROW.GetAttr("oi_escuadra");
					break;
				}
			}                             

			if (oi_horario=="") continue; 

			GetDataSel(MyDAT, oi_horario);
			//Obtengo la definicion del Horario

			horDef=MyDAT["HOR"].arr[oi_horario];

			//calculo posision
			escA=0;      
			if (oi_escuadra!="")
			{
				for (d=0; d<horDef.OPTS.Child.length; d++)
				if (oi_escuadra==horDef.OPTS.Child[d].id)
					escA=parseInt(horDef.OPTS.Child[d].avance,10);
			}
			pos=(t+firstDate+escA) % horDef.largo;     


			if (horDef.TURS.Child[pos]) arr[t]=horDef.TURS.Child[pos].tur;
		}
		arr[arr.length]="0";                    

		//dibujo
		for (d=t=0; t<arr.length; t++)
		{
			if (arr[d]!=arr[t])
			{                 
				if (arr[d]!="0")
				{
					dd=MyDAT["TUR"].arr[arr[d]];

					MyOBJ.SetValue(
						"TUR",
						firstDate+d,
						firstDate+t,
						"Turno",
						dd?dd.color:"AA0000",
						dd?dd.color:"AA0000",
						"Turno "+(dd?dd.label:"")+" desde " + int2date(d+firstDate)+" hasta "+int2date(t+firstDate)
					);
				}

				d=t;
			}
		}
	}

	RefreshCustomSerie(MyOBJ, myserie);
}

function ReDraw(MyOBJ, myserie)
{                            
	if (myserie=="") return;
	var x=myserie.split("|");

	for (var t=0; t<x.length; t++)
	{
		RefreshSerie(MyOBJ, x[t]);
		MyOBJ.ReDraw(x[t]);
	}
}          

var MyREDRAW;         
function ReDrawWait(MyOBJ, myserie, refreshday, refreshcontrol)
{                        
	if (myserie=="") return;     

	MyREDRAW=new Object();
	MyREDRAW.MyOBJ =MyOBJ;
	MyREDRAW.myserie=myserie;

	NomadTimeout((refreshday?"ReDraw(MyREDRAW.MyOBJ, MyREDRAW.myserie);":"")+(refreshcontrol?"RefreshControls();":""),100,"Actualizando la vista...");
}          

function OnChangePeriodo()
{                       
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var lastDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);

	MyOBJ.SetAxisDate(objMONTH.GetXValue()+"01",date2str(lastDate), 1, 1, 12);
	MyOBJ.Draw();

	ReDraw(MyOBJ, "BLQ|HOR|LIC|TUR");
}

