function GetDataSel(MyDAT, oi_horario)
{
	if(MyDAT["HOR"].arr[oi_horario] == null)
	{		
		var PARAM = "<DATO oi_horario=\""+oi_horario+"\"/>";
		proxy=new NomadProxy();	
		var selhor=proxy.SQLService().GetOBJ(Ctrl("main").getResource("SELHOR"),PARAM);
		RESULT=selhor["HORARIOS"];	

		for (t=0; t<RESULT.Child.length; t++)
		{
			MyDAT["HOR"].arr[RESULT.Child[t].id.toString()]=RESULT.Child[t];
			if (MyDAT["HOR"].def==null) MyDAT["HOR"].def=RESULT.Child[t];
		}

		RESULT=selhor["TURNOS"];	

		for (t=0; t<RESULT.Child.length; t++)
		{
			MyDAT["TUR"].arr[RESULT.Child[t].id.toString()]=RESULT.Child[t];
			if (MyDAT["TUR"].def==null) MyDAT["TUR"].def=RESULT.Child[t];
		}
	}
	DrawReference(MyDAT["HOR"], MyDAT["HOR"].cont);
	DrawReference(MyDAT["TUR"], MyDAT["TUR"].cont);
}
